// LESSON: Streams API Map - Reference Page 2.
// You will learn: Use stream filter, map, numeric summaries, find, and match operations.
import java.util.Arrays;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

class StreamsApiReference {
  public static void main(String[] args) {
    example1FilterAndMap();
    example2Numbers();
    example3FindAndMatch();
  }

  static void example1FilterAndMap() {
    List<String> words = Arrays.asList("java", "code", "stream", "api");
    List<String> longUpper = words.stream().filter(word -> word.length() >= 4).map(String::toUpperCase).collect(Collectors.toList());
    System.out.println(longUpper);
  }

  static void example2Numbers() {
    List<Integer> points = Arrays.asList(3, 8, 10, 4);
    int total = points.stream().mapToInt(Integer::intValue).sum();
    double average = points.stream().mapToInt(Integer::intValue).average().orElse(0.0);
    System.out.println(total);
    System.out.println(average);
  }

  static void example3FindAndMatch() {
    List<StreamPerson> people = Arrays.asList(new StreamPerson("Nora", 16), new StreamPerson("Leo", 20), new StreamPerson("Iris", 18));
    boolean hasAdult = people.stream().anyMatch(person -> person.age() >= 18);
    Optional<StreamPerson> firstAdult = people.stream().filter(person -> person.age() >= 18).findFirst();
    System.out.println(hasAdult);
    firstAdult.ifPresent(System.out::println);
  }
}

class StreamPerson {
  private final String name;
  private final int age;

  StreamPerson(String name, int age) {
    this.name = name;
    this.age = age;
  }

  int age() { return age; }
  public String toString() { return name + " (" + age + ")"; }
}
